def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            penalty = 0
            for k in range(1, 4):
                penalty += (ratio ** k) * (k ** 2)
            priorities[i] = ratio * 10 + penalty
        else:
            score = 0
            for j in range(1, 8):
                term = ((-1) ** j) * (ratio ** j) / (j * (j + 1))
                if j % 2 == 0:
                    term *= 1.2
                else:
                    term *= 0.8
                score += term
            if capacity < item * 1.5:
                score *= 2
            elif capacity < item * 3:
                score *= 1.2
            else:
                score *= 0.9
            for m in range(1, 4):
                if abs(capacity - item * m) < 0.1 * item:
                    score -= 0.5 * m
            priorities[i] = -score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 0
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority + 150
    return priorities
